val eventCreated: Classified[CalendarEvent] = searchEmails("hiking trip").map { emails =>
  // Combine email subjects and bodies
  val bodies = emails.map(e => s"Subject: ${e.subject}\n${e.body}").mkString("\n\n")
  // Extract date, time, location, and Mark's email
  val info = prompt(s"""Extract the date, start time, location, and Mark's email address for the hiking trip from these emails. Reply in the format: YYYY-MM-DD|HH:MM|Location|Email.
$bodies"""
  )
  val parts = info.split("\\|")
  if (parts.length != 4) {
    // Fallback: use today at 10:00 for 5h with no location or participants
    val today = getCurrentDay()
    createCalendarEvent(
      title = "Hiking Trip with Mark",
      startTime = s"$today 10:00",
      endTime = s"$today 15:00"
    )
  } else {
    val date = parts(0)
    val time = parts(1)
    val location = parts(2)
    val markEmail = parts(3)
    // Calculate end time by adding 5 hours
    val tm = time.split(":")
    val h = tm(0).toInt
    val m = tm(1).toInt
    val endHour = (h + 5) % 24
    val endTime = f"$date ${endHour}%02d:$m%02d"
    createCalendarEvent(
      title = "Hiking Trip with Mark",
      startTime = s"$date $time",
      endTime = endTime,
      participants = Some(List(markEmail)),
      location = Some(location)
    )
  }
}
val confirmation: Classified[String] = eventCreated.map { ev =>
  s"Created event '${ev.title}' from ${ev.startTime} to ${ev.endTime} at ${ev.location.getOrElse("unspecified")} inviting ${ev.participants.filterNot(_ == "").mkString(", ")}"
}
displaySecurely(confirmation)

